import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static Node insert(Node root, int val) {
        if (root == null) return new Node(val);
        if (val < root.val) root.left = insert(root.left, val);
        else if (val > root.val) root.right = insert(root.right, val);
        // duplicate values are ignored (as per typical BST definition)
        return root;
    }

    // Returns {floor, ceil} where floor is the largest value < key (strictly less)
    // and ceil is the smallest value >= key.
    static int[] floorCeil(Node root, int key) {
        int floor = -1, ceil = -1;
        while (root != null) {
            if (root.val == key) {
                // Ceil includes the key itself.
                ceil = root.val;
                // To find floor (strictly less), continue searching in left subtree.
                root = root.left;
            } else if (root.val < key) {
                floor = root.val; // candidate for floor (strictly less)
                root = root.right;
            } else { // root.val > key
                ceil = root.val; // candidate for ceil (>= key)
                root = root.left;
            }
        }
        return new int[]{floor, ceil};
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int K = Integer.parseInt(st.nextToken());
            Node root = null;
            int read = 0;
            while (read < N) {
                st = new StringTokenizer(br.readLine());
                while (st.hasMoreTokens() && read < N) {
                    int v = Integer.parseInt(st.nextToken());
                    if (v != -1) root = insert(root, v);
                    read++;
                }
            }
            int[] res = floorCeil(root, K);
            out.append(res[0]).append(' ').append(res[1]).append('\n');
        }
        System.out.print(out.toString());
    }
}

